#include "tsp_tst.h"

// Do not edit this file as it will be overwritten if HAMR codegen is rerun

void tsp_tst_initialize(void);
void tsp_tst_notify(microkit_channel channel);
void tsp_tst_timeTriggered(void);

volatile sb_queue_TempControl_SysVerif_Temperature_1_t *currentTemp_queue_1;

#define PORT_FROM_MON 0

bool put_currentTemp(const TempControl_SysVerif_Temperature *data) {
  sb_queue_TempControl_SysVerif_Temperature_1_enqueue((sb_queue_TempControl_SysVerif_Temperature_1_t *) currentTemp_queue_1, (TempControl_SysVerif_Temperature *) data);

  return true;
}

void init(void) {
  printf("%s | INIT!\n", microkit_name);

  sb_queue_TempControl_SysVerif_Temperature_1_init((sb_queue_TempControl_SysVerif_Temperature_1_t *) currentTemp_queue_1);

  tsp_tst_initialize();

  microkit_notify(PORT_FROM_MON);
}

void notified(microkit_channel channel) {
  switch (channel) {
    case PORT_FROM_MON:
      tsp_tst_timeTriggered();
      break;
    default:
      tsp_tst_notify(channel);
  }
}
